from urllib.parse import urlsplit


def flask_redirect():
    '''
    Get the url from the request and redirect to it
    '''
    if 'request' not in globals() or request is None or not hasattr(request, 'args'):
        raise TypeError()

    url = request.args.get('next')
    if not isinstance(url, str):
        raise TypeError()

    url = url.strip()
    if url == "":
        raise ValueError()

    parts = urlsplit(url)
    if parts.scheme or parts.netloc:
        raise ValueError()
    if not url.startswith('/'):
        raise ValueError()

    return url

